import { Str } from '../runtime_common.js';
export class EchoClientJSON {
    constructor(rpc) {
        this.rpc = rpc;
        this.Echo.bind(this);
    }
    Echo(request) {
        const data = Str.toJSON(request);
        const promise = this.rpc.request('devvit.runtime.actor.Echo', 'Echo', 'application/json', data);
        return promise.then((data) => Str.fromJSON(data));
    }
}
export class EchoClientProtobuf {
    constructor(rpc) {
        this.rpc = rpc;
        this.Echo.bind(this);
    }
    Echo(request) {
        const data = Str.encode(request).finish();
        const promise = this.rpc.request('devvit.runtime.actor.Echo', 'Echo', 'application/protobuf', data);
        return promise.then((data) => Str.decode(data));
    }
}
